  1→/**
  2→ * Basement Lab - Workout Tracker
  3→ * State management and UI logic
  4→ */
  5→
  6→const STATE_KEY = 'basement_lab_state';
  7→const LOG_KEY = 'basement_lab_log';
  8→const THEME_KEY = 'basement_lab_theme';
  9→const MODE_KEY = 'basement_lab_mode';
 10→
 11→let programData = null;
 12→let currentState = null;
 13→
 14→// Initialize app
 15→async function init() {
 16→  loadState();
 17→  initTheme();
 18→  await loadProgram();
 19→  render();
 20→  bindEvents();
 21→}
 22→
 23→// Initialize theme and mode from localStorage or system preference
 24→function initTheme() {
 25→  const savedTheme = localStorage.getItem(THEME_KEY) || 'cyberpunk';
 26→  const savedMode = localStorage.getItem(MODE_KEY) ||
 27→    (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark');
 28→
 29→  setTheme(savedTheme);
 30→  setMode(savedMode);
 31→  updateSettingsUI();
 32→}
 33→
 34→// Set theme (cyberpunk, material, ocean, ember)
 35→function setTheme(theme) {
 36→  document.documentElement.setAttribute('data-theme', theme);
 37→  localStorage.setItem(THEME_KEY, theme);
 38→  updateSettingsUI();
 39→}
 40→
 41→// Set mode (dark, light)
 42→function setMode(mode) {
 43→  document.documentElement.setAttribute('data-mode', mode);
 44→  localStorage.setItem(MODE_KEY, mode);
 45→
 46→  // Update meta theme-color based on mode
 47→  const metaThemeColor = document.querySelector('meta[name="theme-color"]');
 48→  if (metaThemeColor) {
 49→    metaThemeColor.setAttribute('content', mode === 'light' ? '#f5f5f5' : '#0a0a0a');
 50→  }
 51→
 52→  updateSettingsUI();
 53→}
 54→
 55→// Update settings modal UI to reflect current theme/mode
 56→function updateSettingsUI() {
 57→  const currentTheme = document.documentElement.getAttribute('data-theme') || 'cyberpunk';
 58→  const currentMode = document.documentElement.getAttribute('data-mode') || 'dark';
 59→
 60→  // Update theme options
 61→  document.querySelectorAll('.theme-option').forEach(option => {
 62→    if (option.dataset.theme === currentTheme) {
 63→      option.classList.add('active');
 64→    } else {
 65→      option.classList.remove('active');
 66→    }
 67→  });
 68→
 69→  // Update mode buttons
 70→  document.querySelectorAll('.mode-btn').forEach(btn => {
 71→    if (btn.dataset.mode === currentMode) {
 72→      btn.classList.add('active');
 73→    } else {
 74→      btn.classList.remove('active');
 75→    }
 76→  });
 77→}
 78→
 79→// Open settings modal
 80→function openSettings() {
 81→  updateSettingsUI();
 82→  document.getElementById('settings-modal').classList.remove('hidden');
 83→}
 84→
 85→// Close settings modal
 86→function closeSettings() {
 87→  document.getElementById('settings-modal').classList.add('hidden');
 88→}
 89→
 90→// Load state from localStorage
 91→function loadState() {
 92→  const saved = localStorage.getItem(STATE_KEY);
 93→  if (saved) {
 94→    currentState = JSON.parse(saved);
 95→    // Validate globalDay: must be a positive integer
 96→    const day = Number(currentState.globalDay);
 97→    if (!Number.isInteger(day) || day < 1) {
 98→      currentState.globalDay = 1;
 99→    } else {
100→      currentState.globalDay = day;
101→    }
102→  } else {
103→    currentState = {
104→      globalDay: 1,
105→      currentPhase: 'p1'
106→    };
107→    saveState();
108→  }
109→}
110→
111→// Save state to localStorage
112→function saveState() {
113→  localStorage.setItem(STATE_KEY, JSON.stringify(currentState));
114→}
115→
116→// Load exercise log from localStorage
117→function loadLog() {
118→  const saved = localStorage.getItem(LOG_KEY);
119→  return saved ? JSON.parse(saved) : {};
120→}
121→
122→// Save exercise log to localStorage
123→function saveLog(log) {
124→  localStorage.setItem(LOG_KEY, JSON.stringify(log));
125→}
126→
127→// Load program data from JSON
128→async function loadProgram() {
129→  try {
130→    const response = await fetch('data/program.json');
131→    programData = await response.json();
132→  } catch (error) {
133→    console.error('Failed to load program:', error);
134→    document.getElementById('workout-name').textContent = 'Error loading program';
135→  }
136→}
137→
138→// Get current phase data
139→function getCurrentPhase() {
140→  if (!programData) return null;
141→  return programData.phases.find(p => p.id === currentState.currentPhase);
142→}
143→
144→// Get workout type for current day
145→function getWorkoutType() {
146→  const phase = getCurrentPhase();
147→  if (!phase || !phase.schedule_pattern) return null;
148→
149→  // Day 1 = index 0, so subtract 1
150→  const dayIndex = (currentState.globalDay - 1) % phase.schedule_pattern.length;
151→  return phase.schedule_pattern[dayIndex];
152→}
153→
154→// Get workout data for current day
155→function getTodaysWorkout() {
156→  const phase = getCurrentPhase();
157→  const workoutType = getWorkoutType();
158→
159→  if (!phase || !workoutType || workoutType === 'Rest') {
160→    return null;
161→  }
162→
163→  return phase.workouts[workoutType];
164→}
165→
166→// Render the UI
167→function render() {
168→  // Update day counter
169→  document.getElementById('current-day').textContent = currentState.globalDay;
170→
171→  const workout = getTodaysWorkout();
172→  const workoutCard = document.getElementById('workout-card');
173→  const restDay = document.getElementById('rest-day');
174→
175→  if (!workout) {
176→    // Rest day
177→    workoutCard.classList.add('hidden');
178→    restDay.classList.remove('hidden');
179→    document.getElementById('session-progress').style.display = 'none';
180→    return;
181→  }
182→
183→  document.getElementById('session-progress').style.display = '';
184→
185→  // Workout day
186→  workoutCard.classList.remove('hidden');
187→  restDay.classList.add('hidden');
188→
189→  document.getElementById('workout-name').textContent = workout.name;
190→  document.getElementById('workout-focus').textContent = workout.focus;
191→
192→  const exercisesList = document.getElementById('exercises-list');
193→  const log = loadLog();
194→
195→  exercisesList.innerHTML = workout.exercises.map((ex, index) => {
196→    const exerciseKey = `${currentState.globalDay}_${index}`;
197→    const logEntry = log[exerciseKey] || {};
198→    const currentWeight = logEntry.weight || '';
199→    const currentDifficulty = logEntry.difficulty || '';
200→    const currentNotes = logEntry.notes || '';
201→
202→    // Calculate suggested weight for weight-based exercises
203→    const suggestedWeight = ex.uses_weight
204→      ? getSuggestedWeight(ex.name, ex.starting_weight, ex.weight_increment || 5)
205→      : null;
206→    const increment = ex.weight_increment || 5;
207→
208→    // Build weight input section
209→    let weightSection = '';
210→    if (ex.uses_weight) {
211→      weightSection = `
212→        <div class="weight-input">
213→          <label>Weight:</label>
214→          <div class="weight-controls">
215→            <button class="weight-btn" data-action="decrement" data-key="${exerciseKey}" data-increment="${increment}">-</button>
216→            <input type="number"
217→                   class="weight-field"
218→                   data-exercise="${ex.name}"
219→                   data-key="${exerciseKey}"
220→                   value="${currentWeight}"
221→                   placeholder="${suggestedWeight}">
222→            <button class="weight-btn" data-action="increment" data-key="${exerciseKey}" data-increment="${increment}">+</button>
223→          </div>
224→          <span class="unit">lbs</span>
225→          <span class="suggested-hint">suggested: ${suggestedWeight}</span>
226→        </div>
227→      `;
228→    } else if (ex.uses_weight !== false) {
229→      // Legacy exercises without uses_weight defined - show basic input
230→      const lastWeight = getLastWeight(ex.name);
231→      weightSection = `
232→        <div class="weight-input">
233→          <label>Weight:</label>
234→          <input type="number"
235→                 class="weight-field"
236→                 data-exercise="${ex.name}"
237→                 data-key="${exerciseKey}"
238→                 value="${currentWeight}"
239→                 placeholder="${lastWeight || '—'}">
240→          <span class="unit">lbs</span>
241→        </div>
242→      `;
243→    }
244→
245→    // Build collapsible feedback section (difficulty + notes)
246→    const isCompleted = logEntry.completed || false;
247→    const hasCustomFeedback = currentDifficulty && currentDifficulty !== 'good' || currentNotes;
248→    const maxSets = ex.sets;
249→    const maxReps = parseReps(ex.reps);
250→    const failedSet = logEntry.failedSet || 1;
251→    const failedRep = logEntry.failedRep || 1;
252→
253→    const feedbackSection = `
254→      <div class="feedback-section${isCompleted && hasCustomFeedback ? ' expanded' : ''}">
255→        <button class="done-btn${isCompleted ? ' is-done' : ''}" data-key="${exerciseKey}" data-exercise="${ex.name}" data-index="${index}">
256→          ${isCompleted ? '\u2713 DONE' : 'DONE'}
257→        </button>
258→        <div class="feedback-content">
259→          <div class="difficulty-input">
260→            <label>How was it?</label>
261→            <div class="difficulty-buttons">
262→              <button class="difficulty-btn${currentDifficulty === 'failed' ? ' selected' : ''}" data-difficulty="failed" data-key="${exerciseKey}" data-exercise="${ex.name}" data-sets="${maxSets}" data-reps="${maxReps}">FAILED</button>
263→              <button class="difficulty-btn${currentDifficulty === 'easy' ? ' selected' : ''}" data-difficulty="easy" data-key="${exerciseKey}" data-exercise="${ex.name}">EASY</button>
264→              <button class="difficulty-btn${currentDifficulty === 'good' || !currentDifficulty ? ' selected' : ''}" data-difficulty="good" data-key="${exerciseKey}" data-exercise="${ex.name}">GOOD</button>
265→              <button class="difficulty-btn${currentDifficulty === 'hard' ? ' selected' : ''}" data-difficulty="hard" data-key="${exerciseKey}" data-exercise="${ex.name}">HARD</button>
266→            </div>
267→          </div>
268→          <div class="failed-details${currentDifficulty === 'failed' ? ' visible' : ''}" data-key="${exerciseKey}">
269→            <div class="slider-group">
270→              <label>Failed on set: <span class="slider-value">${failedSet}</span> / ${maxSets}</label>
271→              <input type="range" class="failed-set-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxSets}" value="${failedSet}">
272→            </div>
273→            <div class="slider-group">
274→              <label>Failed on rep: <span class="slider-value">${failedRep}</span> / ${maxReps}</label>
275→              <input type="range" class="failed-rep-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxReps}" value="${failedRep}">
276→            </div>
277→          </div>
278→          <div class="notes-input">
279→            <textarea class="notes-field" data-key="${exerciseKey}" data-exercise="${ex.name}" placeholder="Notes (optional)">${currentNotes}</textarea>
280→          </div>
281→        </div>
282→      </div>
283→    `;
284→
285→    // Build timer section
286→    let timerSection = '';
287→    const repSeconds = ExerciseTimer.parseSeconds(ex.reps);
288→    const restSeconds = ExerciseTimer.parseSeconds(ex.rest);
289→    if (repSeconds || restSeconds) {
290→      timerSection = '<div class="timer-section">';
291→      if (repSeconds) {
292→        timerSection += ExerciseTimer.renderTimerHTML(
293→          `timer_ex_${currentState.globalDay}_${index}`, repSeconds, 'EXERCISE'
294→        );
295→      }
296→      if (restSeconds) {
297→        timerSection += ExerciseTimer.renderTimerHTML(
298→          `timer_rest_${currentState.globalDay}_${index}`, restSeconds, 'REST'
299→        );
300→      }
301→      timerSection += '</div>';
302→    }
303→
304→    return `
305→      <div class="exercise${isCompleted ? ' completed' : ''}" data-index="${index}">
306→        <div class="exercise-header">
307→          <span class="exercise-name">${ex.name}</span>
308→          ${ex.video_id ? `<button class="video-btn" data-video="${ex.video_id}" data-start="${ex.video_start || 0}">VIDEO</button>` : '<button class="video-btn" disabled>NO VIDEO</button>'}
309→        </div>
310→        <div class="exercise-details">
311→          <span><strong>${ex.sets}</strong> sets</span>
312→          <span><strong>${ex.reps}</strong> reps</span>
313→          <span><strong>${ex.rest}</strong> rest</span>
314→        </div>
315→        ${ex.note ? `<div class="exercise-note">${ex.note}</div>` : ''}
316→        ${timerSection}
317→        ${weightSection}
318→        ${feedbackSection}
319→      </div>
320→    `;
321→  }).join('');
322→
323→  updateProgressBar();
324→  ExerciseTimer.initAll();
325→}
326→
327→// Update session progress bar
328→function updateProgressBar() {
329→  const workout = getTodaysWorkout();
330→  const bar = document.getElementById('session-progress-bar');
331→  if (!workout || !bar) {
332→    if (bar) bar.style.width = '0%';
333→    return;
334→  }
335→
336→  const log = loadLog();
337→  const total = workout.exercises.length;
338→  let completed = 0;
339→
340→  workout.exercises.forEach((ex, index) => {
341→    const key = `${currentState.globalDay}_${index}`;
342→    if (log[key] && log[key].completed) {
343→      completed++;
344→    }
345→  });
346→
347→  const percent = total > 0 ? (completed / total) * 100 : 0;
348→  bar.style.width = `${percent}%`;
349→}
350→
351→// Parse reps string to extract numeric value (e.g., "10/direction" -> 10)
352→function parseReps(repsStr) {
353→  const match = String(repsStr).match(/\d+/);
354→  return match ? parseInt(match[0]) : 10;
355→}
356→
357→// Get the last recorded weight for an exercise
358→function getLastWeight(exerciseName) {
359→  const log = loadLog();
360→  let lastWeight = null;
361→  let lastDay = 0;
362→
363→  for (const key in log) {
364→    if (log[key].exercise === exerciseName && log[key].day > lastDay) {
365→      lastWeight = log[key].weight;
366→      lastDay = log[key].day;
367→    }
368→  }
369→
370→  return lastWeight;
371→}
372→
373→// Get suggested weight with weekly progression logic
374→function getSuggestedWeight(exerciseName, startingWeight, increment = 5) {
375→  const log = loadLog();
376→  const currentWeek = Math.floor((currentState.globalDay - 1) / 7) + 1;
377→
378→  // Find last logged weight for this exercise
379→  let lastEntry = null;
380→  for (const key in log) {
381→    if (log[key].exercise === exerciseName) {
382→      if (!lastEntry || log[key].timestamp > lastEntry.timestamp) {
383→        lastEntry = log[key];
384→      }
385→    }
386→  }
387→
388→  if (!lastEntry) {
389→    return startingWeight; // First time - use starting weight
390→  }
391→
392→  const lastWeek = Math.floor((lastEntry.day - 1) / 7) + 1;
393→
394→  if (currentWeek > lastWeek) {
395→    // New week - suggest progression
396→    return Math.min(lastEntry.weight + increment, 80); // Cap at 80lbs
397→  }
398→
399→  return lastEntry.weight; // Same week - same weight
400→}
401→
402→// Increment weight for an exercise
403→function incrementWeight(exerciseKey, increment = 5) {
404→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
405→  if (!input) return;
406→
407→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 5;
408→  const newValue = Math.min(currentValue + increment, 80); // Cap at 80lbs
409→  input.value = newValue;
410→
411→  // Trigger save
412→  saveWeightInput(input);
413→}
414→
415→// Decrement weight for an exercise
416→function decrementWeight(exerciseKey, increment = 5) {
417→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
418→  if (!input) return;
419→
420→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
421→  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
422→  input.value = newValue;
423→
424→  // Trigger save
425→  saveWeightInput(input);
426→}
427→
428→// Bind event listeners
429→function bindEvents() {
430→  // Settings button
431→  document.getElementById('settings-btn').addEventListener('click', openSettings);
432→
433→  // Settings modal - close on backdrop click
434→  document.getElementById('settings-modal').addEventListener('click', (e) => {
435→    if (e.target.id === 'settings-modal') {
436→      closeSettings();
437→    }
438→  });
439→
440→  // Theme selection
441→  document.querySelectorAll('.theme-option').forEach(option => {
442→    option.addEventListener('click', () => {
443→      setTheme(option.dataset.theme);
444→    });
445→  });
446→
447→  // Mode toggle
448→  document.querySelectorAll('.mode-btn').forEach(btn => {
449→    btn.addEventListener('click', () => {
450→      setMode(btn.dataset.mode);
451→    });
452→  });
453→
454→  // Back button
455→  document.getElementById('back-btn').addEventListener('click', goBack);
456→
457→  // Complete & Advance button
458→  document.getElementById('complete-btn').addEventListener('click', completeWorkout);
459→
460→  // Reset button
461→  document.getElementById('reset-btn').addEventListener('click', resetProgress);
462→
463→  // Video buttons (delegated)
464→  document.getElementById('exercises-list').addEventListener('click', (e) => {
465→    if (e.target.classList.contains('video-btn') && !e.target.disabled) {
466→      openVideo(e.target.dataset.video, e.target.dataset.start);
467→    }
468→  });
469→
470→  // Close modal
471→  document.getElementById('close-modal').addEventListener('click', closeVideo);
472→  document.getElementById('video-modal').addEventListener('click', (e) => {
473→    if (e.target.id === 'video-modal') closeVideo();
474→  });
475→
476→  // Weight inputs (delegated)
477→  document.getElementById('exercises-list').addEventListener('input', (e) => {
478→    if (e.target.classList.contains('weight-field')) {
479→      saveWeightInput(e.target);
480→    }
481→  });
482→
483→  // Weight +/- buttons (delegated)
484→  document.getElementById('exercises-list').addEventListener('click', (e) => {
485→    if (e.target.classList.contains('weight-btn')) {
486→      const action = e.target.dataset.action;
487→      const key = e.target.dataset.key;
488→      const increment = parseInt(e.target.dataset.increment) || 5;
489→
490→      if (action === 'increment') {
491→        incrementWeight(key, increment);
492→      } else if (action === 'decrement') {
493→        decrementWeight(key, increment);
494→      }
495→    }
496→  });
497→
498→  // Difficulty buttons (delegated)
499→  document.getElementById('exercises-list').addEventListener('click', (e) => {
500→    if (e.target.classList.contains('difficulty-btn')) {
501→      const key = e.target.dataset.key;
502→      const difficulty = e.target.dataset.difficulty;
503→      const exercise = e.target.dataset.exercise;
504→
505→      // Update visual selection
506→      const container = e.target.closest('.difficulty-buttons');
507→      container.querySelectorAll('.difficulty-btn').forEach(btn => btn.classList.remove('selected'));
508→      e.target.classList.add('selected');
509→
510→      // Show/hide failed details
511→      const failedDetails = document.querySelector(`.failed-details[data-key="${key}"]`);
512→      if (failedDetails) {
513→        if (difficulty === 'failed') {
514→          failedDetails.classList.add('visible');
515→        } else {
516→          failedDetails.classList.remove('visible');
517→        }
518→      }
519→
520→      // Save to log
521→      saveDifficulty(key, exercise, difficulty);
522→    }
523→  });
524→
525→  // Failed sliders (delegated)
526→  document.getElementById('exercises-list').addEventListener('input', (e) => {
527→    if (e.target.classList.contains('failed-set-slider') || e.target.classList.contains('failed-rep-slider')) {
528→      const slider = e.target;
529→      const key = slider.dataset.key;
530→      const exercise = slider.dataset.exercise;
531→
532→      // Update display value
533→      const label = slider.previousElementSibling;
534→      label.querySelector('.slider-value').textContent = slider.value;
535→
536→      // Save to log
537→      saveFailedDetails(key, exercise);
538→    }
539→  });
540→
541→  // Notes field (delegated)
542→  document.getElementById('exercises-list').addEventListener('input', (e) => {
543→    if (e.target.classList.contains('notes-field')) {
544→      saveNotes(e.target);
545→    }
546→  });
547→
548→  // Done button (delegated)
549→  document.getElementById('exercises-list').addEventListener('click', (e) => {
550→    if (e.target.classList.contains('done-btn')) {
551→      const btn = e.target;
552→      const key = btn.dataset.key;
553→      const exercise = btn.dataset.exercise;
554→      const exerciseCard = btn.closest('.exercise');
555→      const section = btn.closest('.feedback-section');
556→      const log = loadLog();
557→
558→      const wasCompleted = log[key] && log[key].completed;
559→
560→      if (!wasCompleted) {
561→        // Mark as completed, expand feedback
562→        log[key] = {
563→          ...log[key],
564→          exercise: exercise,
565→          completed: true,
566→          day: currentState.globalDay,
567→          timestamp: Date.now()
568→        };
569→        btn.classList.add('is-done');
570→        btn.innerHTML = '\u2713 DONE';
571→        exerciseCard.classList.add('completed');
572→        section.classList.add('expanded');
573→      } else {
574→        // Undo completion
575→        delete log[key].completed;
576→        // If no meaningful data left, remove the entry
577→        if (!log[key].weight && !log[key].difficulty && !log[key].notes) {
578→          delete log[key];
579→        }
580→        btn.classList.remove('is-done');
581→        btn.innerHTML = 'DONE';
582→        exerciseCard.classList.remove('completed');
583→        section.classList.remove('expanded');
584→      }
585→
586→      saveLog(log);
587→      updateProgressBar();
588→    }
589→  });
590→}
591→
592→// Save weight input to log
593→function saveWeightInput(input) {
594→  const log = loadLog();
595→  const key = input.dataset.key;
596→  const weight = input.value;
597→
598→  if (weight) {
599→    // Preserve existing fields when updating weight
600→    log[key] = {
601→      ...log[key],
602→      exercise: input.dataset.exercise,
603→      weight: parseFloat(weight),
604→      day: currentState.globalDay,
605→      timestamp: Date.now()
606→    };
607→  } else if (log[key]) {
608→    // Remove weight but keep other fields if they exist
609→    delete log[key].weight;
610→    // If no meaningful data left, remove the entry
611→    if (!log[key].difficulty && !log[key].notes) {
612→      delete log[key];
613→    }
614→  }
615→
616→  saveLog(log);
617→}
618→
619→// Save difficulty to log
620→function saveDifficulty(key, exercise, difficulty) {
621→  const log = loadLog();
622→
623→  log[key] = {
624→    ...log[key],
625→    exercise: exercise,
626→    difficulty: difficulty,
627→    day: currentState.globalDay,
628→    timestamp: Date.now()
629→  };
630→
631→  // Clear failed details if not failed
632→  if (difficulty !== 'failed') {
633→    delete log[key].failedSet;
634→    delete log[key].failedRep;
635→  }
636→
637→  saveLog(log);
638→}
639→
640→// Save failed set/rep details to log
641→function saveFailedDetails(key, exercise) {
642→  const log = loadLog();
643→  const setSlider = document.querySelector(`.failed-set-slider[data-key="${key}"]`);
644→  const repSlider = document.querySelector(`.failed-rep-slider[data-key="${key}"]`);
645→
646→  log[key] = {
647→    ...log[key],
648→    exercise: exercise,
