  1→#!/usr/bin/env node
  2→/**
  3→ * Validation script for Basement Lab
  4→ * - Validates program.json schema
  5→ * - Checks HTML/JS/CSS syntax
  6→ */
  7→
  8→const fs = require('fs');
  9→const path = require('path');
 10→
 11→const ROOT = path.join(__dirname, '..');
 12→let hasErrors = false;
 13→
 14→function error(msg) {
 15→  console.error(`❌ ${msg}`);
 16→  hasErrors = true;
 17→}
 18→
 19→function success(msg) {
 20→  console.log(`✓ ${msg}`);
 21→}
 22→
 23→// Validate program.json schema
 24→function validateProgramJson() {
 25→  console.log('\n📋 Validating program.json...\n');
 26→
 27→  const programPath = path.join(ROOT, 'data', 'program.json');
 28→
 29→  if (!fs.existsSync(programPath)) {
 30→    error('data/program.json not found');
 31→    return;
 32→  }
 33→
 34→  let program;
 35→  try {
 36→    const content = fs.readFileSync(programPath, 'utf-8');
 37→    program = JSON.parse(content);
 38→    success('Valid JSON syntax');
 39→  } catch (e) {
 40→    error(`Invalid JSON: ${e.message}`);
 41→    return;
 42→  }
 43→
 44→  // Check meta
 45→  if (!program.meta) {
 46→    error('Missing "meta" object');
 47→  } else {
 48→    if (!program.meta.startDate) error('Missing meta.startDate');
 49→    if (!program.meta.version) error('Missing meta.version');
 50→    success('meta object valid');
 51→  }
 52→
 53→  // Check phases
 54→  if (!Array.isArray(program.phases)) {
 55→    error('Missing "phases" array');
 56→    return;
 57→  }
 58→
 59→  program.phases.forEach((phase, i) => {
 60→    const prefix = `phases[${i}]`;
 61→
 62→    if (!phase.id) error(`${prefix}: missing id`);
 63→    if (!phase.name) error(`${prefix}: missing name`);
 64→    if (typeof phase.duration_weeks !== 'number') {
 65→      error(`${prefix}: duration_weeks must be a number`);
 66→    }
 67→
 68→    if (phase.schedule_pattern) {
 69→      if (!Array.isArray(phase.schedule_pattern)) {
 70→        error(`${prefix}: schedule_pattern must be an array`);
 71→      } else if (phase.schedule_pattern.length !== 7) {
 72→        error(`${prefix}: schedule_pattern should have 7 days`);
 73→      }
 74→    }
 75→
 76→    if (phase.workouts && typeof phase.workouts === 'object') {
 77→      Object.entries(phase.workouts).forEach(([key, workout]) => {
 78→        if (!workout.name) error(`${prefix}.workouts.${key}: missing name`);
 79→        if (!Array.isArray(workout.exercises)) {
 80→          error(`${prefix}.workouts.${key}: exercises must be an array`);
 81→        } else {
 82→          workout.exercises.forEach((ex, j) => {
 83→            const exPrefix = `${prefix}.workouts.${key}.exercises[${j}]`;
 84→            if (!ex.name) error(`${exPrefix}: missing name`);
 85→            if (typeof ex.sets !== 'number') error(`${exPrefix}: sets must be a number`);
 86→            if (!ex.reps) error(`${exPrefix}: missing reps`);
 87→          });
 88→        }
 89→      });
 90→      success(`${prefix} workouts valid`);
 91→    }
 92→  });
 93→
 94→  success(`Validated ${program.phases.length} phase(s)`);
 95→}
 96→
 97→// Validate program principles (injury prevention, mobility requirements)
 98→function validatePrinciples() {
 99→  console.log('\n🛡️ Validating program principles...\n');
100→
101→  const programPath = path.join(ROOT, 'data', 'program.json');
102→  let program;
103→
104→  try {
105→    program = JSON.parse(fs.readFileSync(programPath, 'utf-8'));
106→  } catch (e) {
107→    error('Cannot validate principles: program.json parse failed');
108→    return;
109→  }
110→
111→  // Check required principles in meta
112→  const requiredPrinciples = [
113→    'injury_prevention',
114→    'mobility_every_phase',
115→    'form_over_load',
116→    'longevity_focus'
117→  ];
118→
119→  if (!program.meta.principles) {
120→    error('Missing meta.principles array');
121→  } else {
122→    const missing = requiredPrinciples.filter(p => !program.meta.principles.includes(p));
123→    if (missing.length > 0) {
124→      error(`Missing required principles: ${missing.join(', ')}`);
125→    } else {
126→      success('All required principles declared');
127→    }
128→  }
129→
130→  // Check constraints
131→  if (!program.meta.constraints) {
132→    error('Missing meta.constraints object');
133→  } else {
134→    if (!program.meta.constraints.mobility_required) {
135→      error('meta.constraints.mobility_required must be true');
136→    }
137→    if (typeof program.meta.constraints.min_mobility_days_per_week !== 'number' ||
138→        program.meta.constraints.min_mobility_days_per_week < 1) {
139→      error('meta.constraints.min_mobility_days_per_week must be at least 1');
140→    } else {
141→      success('Mobility constraints configured');
142→    }
143→  }
144→
145→  // Check each phase has mobility-focused workout
146→  const mobilityKeywords = ['mobility', 'flexibility', 'recovery', 'stretch', 'flow'];
147→
148→  program.phases.forEach((phase, i) => {
149→    if (!phase.workouts || Object.keys(phase.workouts).length === 0) {
150→      // Skip placeholder phases
151→      return;
152→    }
153→
154→    const workoutNames = Object.values(phase.workouts).map(w => w.name.toLowerCase());
155→    const hasMobility = workoutNames.some(name =>
156→      mobilityKeywords.some(keyword => name.includes(keyword))
157→    );
158→
159→    if (!hasMobility) {
160→      error(`phases[${i}] (${phase.name}): No mobility-focused workout found`);
161→    } else {
162→      success(`phases[${i}] includes mobility work`);
163→    }
164→  });
165→}
166→
167→// Check required files exist
168→function validateFileStructure() {
169→  console.log('\n📁 Validating file structure...\n');
170→
171→  const required = ['index.html', 'style.css', 'app.js', 'data/program.json'];
172→
173→  required.forEach(file => {
174→    const filePath = path.join(ROOT, file);
175→    if (fs.existsSync(filePath)) {
176→      success(`${file} exists`);
177→    } else {
178→      error(`${file} missing`);
179→    }
180→  });
181→}
182→
183→// Basic syntax checks
184→function validateSyntax() {
185→  console.log('\n🔍 Validating syntax...\n');
186→
187→  // Check HTML has required elements
188→  const html = fs.readFileSync(path.join(ROOT, 'index.html'), 'utf-8');
189→
190→  if (!html.includes('<!DOCTYPE html>')) error('index.html: missing DOCTYPE');
191→  if (!html.includes('<meta name="viewport"')) error('index.html: missing viewport meta');
192→  if (!html.includes('app.js')) error('index.html: missing app.js reference');
193→  if (!html.includes('style.css')) error('index.html: missing style.css reference');
194→  if (html.includes('<!DOCTYPE html>')) success('index.html structure valid');
195→
196→  // Check JS for obvious issues
197→  const js = fs.readFileSync(path.join(ROOT, 'app.js'), 'utf-8');
198→
199→  if (!js.includes('localStorage')) error('app.js: missing localStorage usage');
200→  if (!js.includes('fetch')) error('app.js: missing fetch for loading JSON');
201→  if (js.includes('localStorage')) success('app.js uses localStorage');
202→  if (js.includes('fetch')) success('app.js uses fetch API');
203→
204→  // Check CSS has dark theme colors
205→  const css = fs.readFileSync(path.join(ROOT, 'style.css'), 'utf-8');
206→
207→  if (!css.includes(':root')) error('style.css: missing :root variables');
208→  if (!css.includes('--bg-primary')) error('style.css: missing --bg-primary variable');
209→  if (css.includes(':root')) success('style.css uses CSS variables');
210→}
211→
212→// Validate exercise naming (one exercise per entry)
213→function validateExerciseNaming() {
214→  console.log('\n🏷️ Validating exercise naming...\n');
215→
216→  const programPath = path.join(ROOT, 'data', 'program.json');
217→  let program;
